mapper.select:
SELECT DEV_NAME as devName, TIME as time,
fs.title as title, ROUND(t.IO_STAT_AVG,2) as ioStat, ROUND(t.RD_STAT_AVG,2) as rdStat, ROUND(t.WR_STAT_AVG,2) as wrStat, ROUND(t.RD_REQ_PS_AVG,2) AS rdReqps, ROUND(t.WR_REQ_PS_AVG,2) AS wrReqps, ROUND(t.RD_LATENCY_AVG,2) as rdLatency, ROUND(t.WR_LATENCY_AVG,2) as wrLatency, ROUND(t.UTILIZATION_AVG,2) as utilization
any(fs.title) as title, ROUND(sum(t.IO_STAT_AVG),2) as ioStat, ROUND(sum(t.RD_STAT_AVG),2) as rdStat, ROUND(sum(t.WR_STAT_AVG),2) as wrStat, ROUND(sum(t.RD_REQ_PS_AVG),2) AS rdReqps, ROUND(sum(t.WR_REQ_PS_AVG),2) AS wrReqps
FROM (SELECT DEV_NAME, HOST_ID, TIME, avgMerge(IO_STAT_AVG) as IO_STAT_AVG, avgMerge(RD_STAT_AVG) as RD_STAT_AVG, avgMerge(WR_STAT_AVG) as WR_STAT_AVG, avgMerge(RD_REQ_PS_AVG) AS RD_REQ_PS_AVG, avgMerge(WR_REQ_PS_AVG) AS WR_REQ_PS_AVG, avgMerge(RD_LATENCY_AVG) as RD_LATENCY_AVG, avgMerge(WR_LATENCY_AVG) as WR_LATENCY_AVG, avgMerge(UTILIZATION_AVG) as UTILIZATION_AVG FROM AGG_HOST_IO_STAT_1D WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND HOST_ID=${hostId}
AND CLUSTER_ID=${clusterId} AND DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))
AND DEV_NAME =#{currentDisk}
GROUP BY HOST_POOL_ID, CLUSTER_ID, HOST_ID, DEV_NAME, TIME ) t LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} fs on fs.name = t.DEV_NAME
GROUP BY t.DEV_NAME,t.TIME
ORDER BY TIME ASC

SELECT host.name hostName, DEV_NAME as devName, TIME as time, HOST_ID as hostId, ROUND(avgMerge(IO_STAT_AVG),2) as ioStat, ROUND(avgMerge(RD_STAT_AVG),2) as rdStat, ROUND(avgMerge(WR_STAT_AVG),2) as wrStat, ROUND(avgMerge(RD_REQ_PS_AVG),2) AS rdReqps, ROUND(avgMerge(WR_REQ_PS_AVG),2) AS wrReqps, ROUND(avgMerge(RD_LATENCY_AVG),2) as rdLatency, ROUND(avgMerge(WR_LATENCY_AVG),2) as wrLatency, ROUND(avgMerge(UTILIZATION_AVG),2) as utilization, any(fs.title) as title FROM AGG_HOST_IO_STAT_1D t LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_SHARE_FILE_SYSTEM} fs on fs.name = t.DEV_NAME RIGHT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} host ON t.HOST_ID = host.id WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND t.HOST_ID IN (${hostIds})
AND t.CLUSTER_ID =${clusterId}
AND t.DEV_NAME = #{currentDisk}
AND t.DEV_NAME in (select storage_pool_name from ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_STORAGE_POOL_CONFIG} con WHERE con.type in(1,2,9,10))
GROUP BY DEV_NAME, TIME, host.name, HOST_ID ORDER BY TIME ASC

SELECT TD.name as hostName,t.HOST_ID as hostId,
ROUND(sum(IO_STAT_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 86400, 86400, ${endTime} - toUnixTimestamp(TIME))),2) as ioStatSum
FROM (SELECT HOST_ID, DEV_NAME, TIME, avgMerge(IO_STAT_AVG) as IO_STAT_AVG FROM AGG_HOST_IO_STAT_1D FLOW
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND FLOW.HOST_POOL_ID =${hostPoolId}


    AND FLOW.CLUSTER_ID =${clusterId}


    AND FLOW.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY HOST_POOL_ID, CLUSTER_ID, HOST_ID, DEV_NAME, TIME) t,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TD  WHERE TD.id = t.HOST_ID
GROUP BY hostId,hostName ORDER BY ioStatSum DESC

    LIMIT 0,${limit}
